UPDATE articles SET content = '[{"id":"o1","type":"paragraph","text":"Событие начинается с погони двух банд **Vagos** и **Ballas**, которая заканчивается эффектным взрывом на **заправке**. Между преступниками завязывается перестрелка — только вам решать, чью сторону занять."},{"id":"o2","type":"heading2","text":"🔫 Ваш выбор и награды"},{"id":"o3","type":"paragraph","text":"У вас есть три варианта действий, каждый из которых ведёт к разному луту:"},{"id":"o4","type":"step","stepNum":1,"text":"**Помочь банде Ballas** — убейте членов банды Vagos. В благодарность Ballas откроют доступ в **тайник в подвале автомастерской**."},{"id":"o5","type":"step","stepNum":2,"text":"**Помочь банде Vagos** — убейте членов банды Ballas. В награду Vagos дадут код от **тайника в туалете заправки**."},{"id":"o6","type":"step","stepNum":3,"text":"**Перебить всех («Путь одиночки»)** — уничтожьте обе банды и заберите **всю добычу из обоих тайников** себе!"},{"id":"o7","type":"tip","icon":"Совет","text":"Путь одиночки самый сложный, но самый выгодный — вы получаете лут из **обоих** тайников одновременно."}]' WHERE id = 20;

UPDATE articles SET content = '[{"id":"p1","type":"paragraph","text":"На локации **Электростанция** происходит крушение транспортного вертолёта CH47. Ящики с ценным лутом охвачены огнём — ваша задача потушить их с помощью пожарной системы."},{"id":"p2","type":"warning","icon":"Возьмите с собой!","text":"Чтобы попасть на крышу и запустить систему вам понадобятся:\n— **Зелёная карта** (Green Keycard)\n— **Синяя карта** (Blue Keycard)\n— **Предохранитель** (Electric Fuse) — минимум 1 шт."},{"id":"p3","type":"heading2","text":"⚡ Пошаговая инструкция"},{"id":"p4","type":"step","stepNum":1,"text":"**Зачистка:** Прибудьте на Электростанцию (по маркеру на карте) и устраните охрану NPC."},{"id":"p5","type":"step","stepNum":2,"text":"**Проход на крышу:** Используйте карты и предохранитель чтобы открыть двери и подняться на **крышу здания**."},{"id":"p6","type":"step","stepNum":3,"text":"**Доставка воды:** Дождитесь прибытия поезда — он привезёт бочку с водой к зданию."},{"id":"p7","type":"step","stepNum":4,"text":"**Заправка:** Перенесите воду из поезда (рядом есть пустые канистры в ящике) в пустую бочку на крыше и нажмите кнопку запуска системы."},{"id":"p8","type":"step","stepNum":5,"text":"**Сбор лута:** Огонь в градирне потухнет — теперь можно безопасно забирать лут из ящиков."},{"id":"p9","type":"warning","icon":"Важно!","text":"Без карт и предохранителя вы не сможете нажать кнопку пожаротушения!"}]' WHERE id = 21;
